import type { HTMLAttributes } from 'react';
export type SkeletonVariant = 'line' | 'circle' | 'square' | 'text' | 'title';
export type SkeletonValue = number | string;
export type SkeletonMargin = {
    bottom?: SkeletonValue;
    left?: SkeletonValue;
    right?: SkeletonValue;
    top?: SkeletonValue;
} | SkeletonValue;
export interface SkeletonProps extends HTMLAttributes<HTMLDivElement> {
    /** Включает или отключает анимацию */
    animated?: boolean;
    /** Высота */
    height?: SkeletonValue;
    /** Внешние отступы. Можно передать объект с указанием направления внешнего отступа ({top: 0, right: 0, ...}) */
    margin?: SkeletonMargin;
    /** Радиус округления */
    radius?: SkeletonValue;
    /** Тип, влияет на форму */
    variant?: SkeletonVariant;
    /** Ширина */
    width?: SkeletonValue;
}
